function sanitizeFilePart(value) {
  return String(value || '')
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/ß/g, 'ss')
    .replace(/[^a-zA-Z0-9]+/g, '-')
    .replace(/^-+|-+$/g, '')
    .slice(0, 48);
}

const body = $json.body || $json;
const originalName = body.originalFileName || body.normalizedFileName || 'Dokument.pdf';
const extension = String(originalName).match(/\.([a-zA-Z0-9]{1,8})$/)?.[0]?.toLowerCase() || '.pdf';
const date = new Date().toISOString().slice(0, 10);
const area = body.area || 'Unsortiert';
const documentType = body.documentType || 'Dokument';
const normalizedFileName = body.normalizedFileName || [
  date,
  sanitizeFilePart(area),
  sanitizeFilePart(documentType),
  'Murat-Kocyigit',
  sanitizeFilePart(originalName.replace(/\.[^.]+$/, ''))
].filter(Boolean).join('_') + extension;

return [{
  json: {
    area,
    documentType,
    normalizedFileName,
    personName: body.personName || 'Murat Kocyigit',
    documentId: `DOC-${Date.now()}`,
    incomingDate: date,
    sheetId: '1FEnhO0S8fZzzoEKbXVLyX6mn6Su25GIZ4bJbtwd3eks',
    driveFolderId: 'GOOGLE_DRIVE_EINGANG_FOLDER_ID_HERE'
  },
  binary: $binary
}];

